/**
 * Tiny inline media for the cookbook demo casts.
 *
 * Video- and audio-output recipes need a real clip/track to render inside the
 * node content cards, but the casts must stay backend-free and self-contained
 * (like the kitten image in `exampleImage.ts`). These are minimal placeholders
 * generated once: a 2-second 320px WebM (VP8) and a 0.7-second mono WAV chime,
 * inlined as base64 data URIs so they resolve with no asset pinning in both the
 * Remotion render and the in-app demo player.
 */

/** A short, silent placeholder clip shown in video-generator content cards. */
export const SAMPLE_VIDEO_WEBM_DATA_URI =
  "data:video/webm;base64,";

/** A short placeholder track shown in audio-output content cards. */
export const SAMPLE_AUDIO_WAV_DATA_URI =
  "data:audio/wav;base64,";

